class InvokeRuntime:
    def __init__(self, verbose: bool = False, provider: str = "agentcube") -> None:
        self.verbose = verbose
        self.provider = provider

    def invoke(
        self, workspace_path: Path, payload: Dict[str, Any], headers: Optional[Dict[str, str]] = None
    ) -> Any:
        import httpx

        metadata, endpoint, rewrite_url = self._validate_invoke_prerequisites(workspace_path)

        request_headers = headers or {}
        if metadata.session_id:
            request_headers["X-Agentcube-Session-Id"] = metadata.session_id

        url = endpoint
        if rewrite_url:
            url = rewrite_url

        with httpx.Client(timeout=120.0) as client:
            response = client.post(url, json=payload, headers=request_headers)
            response.raise_for_status()
            return response.json()

    def _validate_invoke_prerequisites(self, workspace_path: Path) -> Tuple[Any, str, str]:
        import yaml

        metadata_file = workspace_path / "agent_metadata.yaml"
        if not metadata_file.exists():
            metadata_file = workspace_path / "agent.yaml"
        if not metadata_file.exists():
            metadata_file = workspace_path / "metadata.yaml"

        if not metadata_file.exists():
            raise ValueError("No agent metadata found. Run 'pack' first.")

        with open(metadata_file, "r") as f:
            data = yaml.safe_load(f) or {}

        from .services.metadata_service import AgentMetadata
        metadata = AgentMetadata(**data)

        if not metadata.agent_endpoint:
            raise ValueError("Agent not published. Run 'publish' first.")

        endpoint = metadata.agent_endpoint
        rewrite_url = ""

        if metadata.k8s_deployment and metadata.k8s_deployment.get("type") == "AgentRuntime":
            rewrite_url = f"{endpoint}/v1/namespaces/{metadata.k8s_deployment.get('namespace', 'default')}/agent-runtimes/{metadata.agent_name}/invocations/"

        return metadata, endpoint, rewrite_url

