"""Docker Service"""

import time
from pathlib import Path
from typing import Any, Dict, Optional


class DockerService:
    def __init__(self, verbose: bool = False) -> None:
        self.verbose = verbose
        self._client = None

    @property
    def client(self):
        if self._client is None:
            import docker
            self._client = docker.from_env()
        return self._client

    def check_docker_available(self) -> bool:
        try:
            self.client.ping()
            return True
        except Exception:
            return False

    def build_image(
        self,
        dockerfile_path: Path,
        context_path: Path,
        image_name: str,
        tag: str = "latest",
        build_args: Optional[Dict[str, str]] = None,
    ) -> Dict[str, str]:
        start_time = time.time()

        full_name = f"{image_name}:{tag}"

        build_kwargs = {
            "path": str(context_path),
            "dockerfile": str(dockerfile_path.name),
            "tag": full_name,
        }
        if build_args:
            build_kwargs["buildargs"] = build_args

        image, build_logs = self.client.images.build(**build_kwargs)

        build_time = time.time() - start_time

        return {
            "image_name": image_name,
            "image_id": image.id,
            "image_size": self._format_size(image.attrs["Size"]),
            "build_time": f"{build_time:.2f}s",
            "tag": tag,
        }

    def get_image_info(self, image_name: str) -> Dict[str, str]:
        return self._get_image_info(image_name)

    def _get_image_info(self, image_name: str) -> Dict[str, str]:
        try:
            image = self.client.images.get(image_name)
            return {
                "name": image_name,
                "id": image.id,
                "size": self._format_size(image.attrs["Size"]),
                "created": image.attrs["Created"],
            }
        except Exception:
            return {"name": image_name, "error": "Image not found"}

    def _format_size(self, size_bytes: int) -> str:
        for unit in ["B", "KB", "MB", "GB"]:
            if size_bytes < 1024:
                return f"{size_bytes:.2f} {unit}"
            size_bytes /= 1024
        return f"{size_bytes:.2f} TB"

    def push_image(
        self,
        image_name: str,
        registry_url: Optional[str] = None,
        username: Optional[str] = None,
        password: Optional[str] = None,
    ) -> Dict[str, str]:
        start_time = time.time()

        if username and password:
            self._docker_login_sdk(registry_url, username, password)

        target_image = image_name
        if registry_url:
            target_image = f"{registry_url}/{image_name}"
            self._tag_image_sdk(image_name, target_image)

        push_logs = self.client.images.push(target_image)
        push_time = time.time() - start_time

        return {
            "pushed_image": target_image,
            "push_time": f"{push_time:.2f}s",
        }

    def _docker_login_sdk(self, registry: Optional[str], username: str, password: str) -> None:
        self.client.login(username=username, password=password, registry=registry)

    def _tag_image_sdk(self, source_image: str, target_image: str) -> None:
        self.client.images.get(source_image).tag(target_image)

    def remove_image(self, image_name: str) -> bool:
        try:
            self.client.images.remove(image_name)
            return True
        except Exception as e:
            if self.verbose:
                print(f"Warning: Failed to remove image {image_name}: {e}")
            return False

"""Kubernetes Provider"""

import os
from typing import Any, Dict, Optional


class KubernetesProvider:
    def __init__(
        self,
        namespace: str = "default",
        verbose: bool = False,
        kubeconfig: Optional[str] = None,
    ) -> None:
        self.namespace = namespace
        self.verbose = verbose
        self.kubeconfig = kubeconfig
        self._api = None
        self._apps_api = None

    @property
    def api(self):
        if self._api is None:
            from kubernetes import client, config
            if self.kubeconfig:
                config.load_kube_config(config_file=self.kubeconfig)
            elif os.path.exists(os.path.expanduser("~/.kube/config")):
                config.load_kube_config()
            else:
                config.load_incluster_config()
            self._api = client.CoreV1Api()
        return self._api

    @property
    def apps_api(self):
        if self._apps_api is None:
            from kubernetes import client
            self._apps_api = client.AppsV1Api()
        return self._apps_api

    def _ensure_namespace(self) -> None:
        from kubernetes import client
        try:
            self.api.read_namespace(self.namespace)
        except client.exceptions.ApiException as e:
            if e.status == 404:
                ns = client.V1Namespace(metadata=client.V1ObjectMeta(name=self.namespace))
                self.api.create_namespace(ns)

    def deploy_agent(
        self,
        agent_name: str,
        image_url: str,
        port: int,
        entrypoint: Optional[str] = None,
        replicas: int = 1,
        node_port: Optional[int] = None,
        env_vars: Optional[Dict[str, str]] = None,
    ) -> Dict[str, Any]:
        self._ensure_namespace()
        name = self._sanitize_name(agent_name)

        deployment_result = self._create_deployment(name, image_url, port, entrypoint, replicas, env_vars)
        service_result = self._create_service(name, port, node_port)

        return {
            "deployment_name": name,
            "service_name": name,
            "namespace": self.namespace,
            "replicas": replicas,
            "container_port": port,
            "node_port": service_result.get("node_port"),
            "service_url": service_result.get("service_url"),
        }

    def _create_deployment(
        self,
        name: str,
        image_url: str,
        port: int,
        entrypoint: Optional[str],
        replicas: int,
        env_vars: Optional[Dict[str, str]],
    ) -> Dict[str, Any]:
        from kubernetes import client

        env_list = []
        if env_vars:
            env_list = [client.V1EnvVar(name=k, value=v) for k, v in env_vars.items()]

        container = client.V1Container(
            name=name,
            image=image_url,
            ports=[client.V1ContainerPort(container_port=port)],
            env=env_list,
        )

        if entrypoint:
            parts = entrypoint.split()
            container.command = parts

        template = client.V1PodTemplateSpec(
            metadata=client.V1ObjectMeta(labels={"app": name}),
            spec=client.V1PodSpec(containers=[container]),
        )

        spec = client.V1DeploymentSpec(
            replicas=replicas,
            selector=client.V1LabelSelector(match_labels={"app": name}),
            template=template,
        )

        deployment = client.V1Deployment(
            api_version="apps/v1",
            kind="Deployment",
            metadata=client.V1ObjectMeta(name=name, namespace=self.namespace),
            spec=spec,
        )

        try:
            self.apps_api.create_namespaced_deployment(self.namespace, deployment)
        except client.exceptions.ApiException as e:
            if e.status == 409:
                self.apps_api.patch_namespaced_deployment(name, self.namespace, deployment)
            else:
                raise

        return {"name": name}

    def _create_service(self, name: str, port: int, node_port: Optional[int]) -> Dict[str, Any]:
        from kubernetes import client

        spec_kwargs = {
            "selector": {"app": name},
            "ports": [client.V1ServicePort(port=port, target_port=port, node_port=node_port)],
            "type": "NodePort" if node_port else "ClusterIP",
        }

        service = client.V1Service(
            api_version="v1",
            kind="Service",
            metadata=client.V1ObjectMeta(name=name, namespace=self.namespace),
            spec=client.V1ServiceSpec(**spec_kwargs),
        )

        try:
            result = self.api.create_namespaced_service(self.namespace, service)
        except client.exceptions.ApiException as e:
            if e.status == 409:
                result = self.api.patch_namespaced_service(name, self.namespace, service)
            else:
                raise

        service_url = f"http://localhost:{port}"
        if result.spec.type == "NodePort" and result.spec.ports:
            node_port = result.spec.ports[0].node_port
            service_url = f"http://localhost:{node_port}"

        return {"name": name, "node_port": node_port, "service_url": service_url}

    def wait_for_deployment_ready(self, name: str, timeout: int = 120) -> None:
        import time

        start = time.time()
        while time.time() - start < timeout:
            deployment = self.apps_api.read_namespaced_deployment(name, self.namespace)
            if deployment.status.ready_replicas == deployment.spec.replicas:
                return
            time.sleep(2)
        raise TimeoutError(f"Deployment {name} not ready within {timeout} seconds")

    def get_agent_status(self, agent_name: str) -> Dict[str, Any]:
        from kubernetes import client

        name = self._sanitize_name(agent_name)
        try:
            deployment = self.apps_api.read_namespaced_deployment(name, self.namespace)
            service = self.api.read_namespaced_service(name, self.namespace)

            return {
                "status": "running" if deployment.status.ready_replicas else "pending",
                "deployment_name": name,
                "namespace": self.namespace,
                "replicas": deployment.spec.replicas,
                "ready_replicas": deployment.status.ready_replicas or 0,
                "service_url": f"http://localhost:{service.spec.ports[0].node_port}" if service.spec.type == "NodePort" else f"http://{name}.{self.namespace}.svc.cluster.local:{service.spec.ports[0].port}",
            }
        except client.exceptions.ApiException as e:
            if e.status == 404:
                return {"status": "not_found", "deployment_name": name}
            raise

    def delete_agent(self, agent_name: str) -> Dict[str, Any]:
        from kubernetes import client

        name = self._sanitize_name(agent_name)
        try:
            self.apps_api.delete_namespaced_deployment(name, self.namespace)
        except client.exceptions.ApiException as e:
            if e.status != 404:
                raise

        try:
            self.api.delete_namespaced_service(name, self.namespace)
        except client.exceptions.ApiException as e:
            if e.status != 404:
                raise

        return {"status": "deleted", "deployment_name": name, "namespace": self.namespace}

    def _sanitize_name(self, name: str) -> str:
        return name.lower().replace("_", "-").replace(".", "-")

