                        "containers": [
                            {
                                "name": name,
                                "image": image_url,
                                "ports": [{"containerPort": port}],
                            }
                        ]
                    }
                },
            },
        }

        if env:
            body["spec"]["podTemplate"]["spec"]["containers"][0]["env"] = [
                {"name": k, "value": v} for k, v in env.items()
            ]

        if entrypoint:
            body["spec"]["podTemplate"]["spec"]["containers"][0]["command"] = entrypoint.split()

        if readiness_probe_path:
            body["spec"]["podTemplate"]["spec"]["containers"][0]["readinessProbe"] = {
                "httpGet": {
                    "path": readiness_probe_path,
                    "port": readiness_probe_port or port,
                }
            }

        body["spec"]["podTemplate"]["spec"]["imagePullSecrets"] = [{"name": "default-secret"}]

        try:
            self.api.create_namespaced_custom_object(
                group="runtime.agentcube.volcano.sh",
                version="v1alpha1",
                namespace=self.namespace,
                plural="agentruntimes",
