                self.api.patch_namespaced_custom_object(
                    group="runtime.agentcube.volcano.sh",
                    version="v1alpha1",
                    namespace=self.namespace,
                    plural="agentruntimes",
                    name=name,
                    body=body,
                )
            else:
                raise

        return {
            "agent_name": name,
            "agent_id": name,
            "namespace": self.namespace,
            "endpoint": f"{router_url}/v1/namespaces/{self.namespace}/agent-runtimes/{name}/invocations/" if router_url else "",
        }

    def _sanitize_name(self, name: str) -> str:
        return name.lower().replace("_", "-").replace(".", "-")

    def get_agent_runtime(self, name: str, namespace: str) -> Optional[Dict[str, Any]]:
        try:
            return self.api.get_namespaced_custom_object(
                group="runtime.agentcube.volcano.sh",
                version="v1alpha1",
                namespace=namespace,
                plural="agentruntimes",
